const mongoose = require('mongoose');
const express = require('express');

function queryBuilder(filter, projection, sort) {
    return async (req, res) => {
        try {
            // Merge dynamic filters from request body with static filter object
            const combinedFilter = { ...filter, ...req.body.filter };
            
            // Merge dynamic projection and sort criteria if provided in the request
            const combinedProjection = { ...projection, ...(req.query.fields && JSON.parse(req.query.fields)) };
            const combinedSort = { ...sort, ...(req.query.sort && JSON.parse(req.query.sort)) };

            // Execute query using Mongoose model.find with combined filter, projection, and sort
            const results = await req.model.find(combinedFilter, combinedProjection).sort(combinedSort);

            res.json(results);
        } catch (error) {
            console.error(error);
            res.status(500).json({ error: 'An error occurred while processing your request' });
        }
    };
}

